'use client'

import { useMemo, useRef, useState } from 'react'
import { supabase, supabaseEnabled } from '../lib/supabase'

const initialForm = {
  camperFirstName: '',
  camperLastName: '',
  age: '',
  experienceLevel: 'beginner',
  guardianName: '',
  guardianEmail: '',
  guardianPhone: '',
  emergencyContact: '',
  medicalNotes: '',
}

const steps = [
  { id: 1, title: 'Camper details' },
  { id: 2, title: 'Guardian details' },
  { id: 3, title: 'Review & submit' },
]

const perks = [
  {
    title: 'Daily training tracks',
    text: 'Age-based groups for movement, drills, confidence, and skill progress.',
  },
  {
    title: 'Certified coaches',
    text: 'Experienced instructors with first-aid awareness and youth coaching focus.',
  },
  {
    title: 'Weekly showcase',
    text: 'Campers demonstrate progress every Friday in a short family showcase.',
  },
]

const campTypes = [
  {
    name: 'Dragon Start Camp',
    audience: 'General curriculum, beginner friendly, ages 3+',
    details:
      'Perfect first camp experience with movement, balance, coordination, and fun fundamentals.',
    note: 'Best fit for new students and families exploring Wushu.',
  },
  {
    name: 'Competition Team Boot Camp',
    audience: 'For Taolu team and serious competition-track students',
    details:
      'Focused technical training, routine polish, performance quality, and competition mindset.',
    note: 'Two weeks required for students who want to join the fall competition team.',
  },
  {
    name: 'Overnight Camp',
    audience: 'Immersive training and camp-life experience',
    details:
      'Great for building friendships with intensive Wushu training, a fun camp atmosphere, and scheduled outings across all 7 days.',
    note: 'Limited spots and always a hit.',
  },
]

const schedule = [
  { day: 'Monday', activity: 'Footwork foundations + team games' },
  { day: 'Tuesday', activity: 'Technique stations + confidence drills' },
  { day: 'Wednesday', activity: 'Agility circuits + partner practice' },
  { day: 'Thursday', activity: 'Mini challenges + supervised sparring' },
  { day: 'Friday', activity: 'Showcase prep + parent performance' },
]

const levelUpFeatures = [
  'Track skill progress week by week in the Level Up app.',
  'Campers earn points for consistency, effort, and positive attitude.',
  'Points unlock rewards and teach merit, discipline, and hard work.',
  'Points can also translate into future camp discounts for families.',
]

export default function HomePage() {
  const [step, setStep] = useState(1)
  const [submitting, setSubmitting] = useState(false)
  const [message, setMessage] = useState('')
  const [form, setForm] = useState(initialForm)
  const registrationRef = useRef(null)

  const missingConfig = useMemo(() => !supabaseEnabled, [])

  function updateField(event) {
    const { name, value } = event.target
    setForm((current) => ({ ...current, [name]: value }))
  }

  function jumpToRegistration() {
    registrationRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' })
  }

  function validateStep(currentStep) {
    if (currentStep === 1) {
      return (
        form.camperFirstName.trim() &&
        form.camperLastName.trim() &&
        Number(form.age) >= 3 &&
        Number(form.age) <= 17
      )
    }

    if (currentStep === 2) {
      return (
        form.guardianName.trim() &&
        /\S+@\S+\.\S+/.test(form.guardianEmail) &&
        form.guardianPhone.trim() &&
        form.emergencyContact.trim()
      )
    }

    return true
  }

  function nextStep() {
    if (!validateStep(step)) {
      setMessage('Please complete all required fields for this step.')
      return
    }

    setMessage('')
    setStep((current) => Math.min(current + 1, 3))
  }

  function previousStep() {
    setMessage('')
    setStep((current) => Math.max(current - 1, 1))
  }

  async function submitRegistration(event) {
    event.preventDefault()

    if (!supabaseEnabled || !supabase) {
      setMessage('Add your Supabase URL and anon key to submit registrations.')
      return
    }

    setSubmitting(true)
    setMessage('')

    const payload = {
      camper_first_name: form.camperFirstName.trim(),
      camper_last_name: form.camperLastName.trim(),
      age: Number(form.age),
      experience_level: form.experienceLevel,
      guardian_name: form.guardianName.trim(),
      guardian_email: form.guardianEmail.trim(),
      guardian_phone: form.guardianPhone.trim(),
      emergency_contact: form.emergencyContact.trim(),
      medical_notes: form.medicalNotes.trim() || null,
      created_at: new Date().toISOString(),
    }

    const { error } = await supabase.from('registrations').insert(payload)

    if (error) {
      setSubmitting(false)
      setMessage(`Submission failed: ${error.message}`)
      return
    }

    setSubmitting(false)
    setMessage('Registration submitted successfully.')
    setForm(initialForm)
    setStep(1)
  }

  return (
    <main className="page">
      <section className="hero card">
        <p className="eyebrow">New England Wushu Summer Camp 2026</p>
        <h1>Train hard, build confidence, and have a summer kids remember.</h1>
        <p className="subhead">
          Ages 6-17. Small groups, skill-based coaching, and weekly family showcases.
        </p>

        <div className="heroActions">
          <button type="button" className="button" onClick={jumpToRegistration}>
            Start Registration
          </button>
          <a className="ghostBtn" href="#program">
            View Program
          </a>
        </div>

        <div className="heroStats">
          <article>
            <strong>8 weeks</strong>
            <span>June to August</span>
          </article>
          <article>
            <strong>1:8 ratio</strong>
            <span>Coach to camper</span>
          </article>
          <article>
            <strong>3 levels</strong>
            <span>Beginner to advanced</span>
          </article>
        </div>
      </section>

      <section id="program" className="card section">
        <h2>Why families choose this camp</h2>
        <div className="perkGrid">
          {perks.map((item) => (
            <article key={item.title} className="perkCard">
              <h3>{item.title}</h3>
              <p>{item.text}</p>
            </article>
          ))}
        </div>
      </section>

      <section className="card section">
        <h2>Choose your camp type</h2>
        <div className="perkGrid">
          {campTypes.map((camp) => (
            <article key={camp.name} className="perkCard">
              <h3>{camp.name}</h3>
              <p>
                <strong>{camp.audience}</strong>
              </p>
              <p>{camp.details}</p>
              <p className="note">{camp.note}</p>
            </article>
          ))}
        </div>
      </section>

      <section className="card section">
        <h2>Weekly structure</h2>
        <div className="scheduleList">
          {schedule.map((item) => (
            <article key={item.day} className="scheduleItem">
              <strong>{item.day}</strong>
              <p>{item.activity}</p>
            </article>
          ))}
        </div>
      </section>

      <section className="card section levelUpSection">
        <div className="phoneMock" aria-hidden="true">
          <div className="phoneFrame">
            <div className="phoneNotch" />
            <div className="phoneScreen">
              <p>Level Up app screenshot goes here</p>
            </div>
          </div>
        </div>

        <div className="levelUpContent">
          <p className="eyebrow">Level Up App</p>
          <h2>Progress tracking that motivates kids all summer</h2>
          <p className="subhead">
            We incorporate our Level Up app into camp so families can see growth and kids stay excited about
            improving every week.
          </p>

          <div className="featureList">
            {levelUpFeatures.map((feature) => (
              <article key={feature} className="featureItem">
                {feature}
              </article>
            ))}
          </div>
        </div>
      </section>

      <section ref={registrationRef} className="card section" id="register">
        <header>
          <h2>Registration flow</h2>
          <p className="subhead">
            Complete the 3-step form below. You can review everything before submission.
          </p>
        </header>

        <ol className="stepper" aria-label="Registration steps">
          {steps.map((item) => (
            <li key={item.id} className={item.id <= step ? 'active' : ''}>
              <span>{item.id}</span>
              {item.title}
            </li>
          ))}
        </ol>

        {missingConfig ? (
          <div className="warning">
            Missing environment variables. Copy <code>.env.example</code> to <code>.env</code> and add your
            Supabase project values.
          </div>
        ) : null}

        <form onSubmit={submitRegistration}>
          {step === 1 ? (
            <div className="grid">
              <label>
                Camper first name
                <input name="camperFirstName" value={form.camperFirstName} onChange={updateField} required />
              </label>

              <label>
                Camper last name
                <input name="camperLastName" value={form.camperLastName} onChange={updateField} required />
              </label>

              <label>
                Age (3-17)
                <input
                  name="age"
                  type="number"
                  min="3"
                  max="17"
                  value={form.age}
                  onChange={updateField}
                  required
                />
              </label>

              <label>
                Experience level
                <select name="experienceLevel" value={form.experienceLevel} onChange={updateField}>
                  <option value="beginner">Beginner</option>
                  <option value="intermediate">Intermediate</option>
                  <option value="advanced">Advanced</option>
                </select>
              </label>
            </div>
          ) : null}

          {step === 2 ? (
            <div className="grid">
              <label>
                Guardian full name
                <input name="guardianName" value={form.guardianName} onChange={updateField} required />
              </label>

              <label>
                Guardian email
                <input
                  name="guardianEmail"
                  type="email"
                  value={form.guardianEmail}
                  onChange={updateField}
                  required
                />
              </label>

              <label>
                Guardian phone
                <input name="guardianPhone" value={form.guardianPhone} onChange={updateField} required />
              </label>

              <label>
                Emergency contact
                <input name="emergencyContact" value={form.emergencyContact} onChange={updateField} required />
              </label>

              <label className="full">
                Medical notes (optional)
                <textarea name="medicalNotes" value={form.medicalNotes} onChange={updateField} rows="4" />
              </label>
            </div>
          ) : null}

          {step === 3 ? (
            <div className="review">
              <h3>Review details</h3>
              <ul>
                <li>
                  Camper: {form.camperFirstName} {form.camperLastName}, age {form.age}
                </li>
                <li>Experience: {form.experienceLevel}</li>
                <li>Guardian: {form.guardianName}</li>
                <li>Email: {form.guardianEmail}</li>
                <li>Phone: {form.guardianPhone}</li>
                <li>Emergency contact: {form.emergencyContact}</li>
                <li>Medical notes: {form.medicalNotes || 'None provided'}</li>
              </ul>
            </div>
          ) : null}

          <div className="actions">
            {step > 1 ? (
              <button type="button" className="button secondary" onClick={previousStep}>
                Back
              </button>
            ) : (
              <span />
            )}

            {step < 3 ? (
              <button type="button" className="button" onClick={nextStep}>
                Continue
              </button>
            ) : (
              <button className="button" type="submit" disabled={submitting}>
                {submitting ? 'Submitting...' : 'Submit registration'}
              </button>
            )}
          </div>
        </form>

        {message ? <p className="message">{message}</p> : null}
      </section>
    </main>
  )
}
